import java.nio.charset.StandardCharsets;
import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        byte[] inputBytes = input.getBytes(StandardCharsets.UTF_8);

        // Use a dynamic buffer size based on input length
        char[] buffer = new char[inputBytes.length];

        // Copy user input into the buffer with proper length check
        for (int i = 0; i < inputBytes.length && i < buffer.length; i++) {
            buffer[i] = (char) inputBytes[i];
        }

        System.out.println("Input successfully stored in buffer: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
